const now = new Date();
const cetFormatter = new Intl.DateTimeFormat('fr-FR', {
  timeZone: 'Europe/Paris',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour12: false
});

const parts = cetFormatter.formatToParts(now);
const year = parts.find(p => p.type === 'year').value;
const month = parts.find(p => p.type === 'month').value;
const day = parts.find(p => p.type === 'day').value;

const today = `${year}-${month}-${day}`;
const cetMidnight = new Date(`${today}T00:00:00+01:00`);
const timestamp = Math.floor(cetMidnight.getTime() / 1000);

return [{ json: { today, timestamp, iso: now.toISOString() } }];

const queryResult = $('Query Prospects Contactes').first().json;
const results = queryResult.results || [];
const count = Array.isArray(results) ? results.length : 0;

const names = [];
if (Array.isArray(results)) {
  for (const page of results) {
    const props = page.properties || {};
    const nomProp = props['Nom'] || props['Name'] || {};
    const titleArr = nomProp.title || [];
    const name = titleArr.map(t => t.plain_text || '').join('') || 'Sans nom';
    const statusProp = props['Status'] || {};
    const status = (statusProp.select || {}).name || '?';
    names.push(`${name} (${status})`);
  }
}

const ctx = $('Date Context').first().json;

return [{
  json: {
    value: count,
    timestamp: ctx.timestamp,
    comment: `Auto-sync: ${count} prospect(s) contacte(s) le ${ctx.today}` + (names.length > 0 ? ' — ' + names.join(', ') : ''),
    label: 'Prospection',
    names
  }
}];

const queryResult = $('Query Daily Judgment').first().json;
const results = queryResult.results || [];

let doucheFroide = false;
let journaling = false;
const details = [];

if (Array.isArray(results)) {
  for (const page of results) {
    const props = page.properties || {};
    const nameProp = props['Name'] || props['name'] || {};
    const titleArr = nameProp.title || [];
    const title = titleArr.map(t => t.plain_text || '').join('').toLowerCase();

    if (title.includes('douche') || title.includes('cold') || title.includes('froide')) {
      doucheFroide = true;
      details.push('Douche Froide');
    }
    if (title.includes('journal') || title.includes('journaling')) {
      journaling = true;
      details.push('Journaling');
    }
  }
}

// Count only these 2 habits (push-ups sent separately by the app)
const score = (doucheFroide ? 1 : 0) + (journaling ? 1 : 0);

const ctx = $('Date Context').first().json;

return [{
  json: {
    value: score,
    timestamp: ctx.timestamp,
    comment: `Auto-sync: ${details.length > 0 ? details.join(' + ') : 'aucune habitude detectee'} (${score}/2 via Notion) le ${ctx.today}`,
    label: 'Habitudes',
    doucheFroide,
    journaling,
    details
  }
}];

let prospectionData, habitudesData;

try {
  prospectionData = $('Process Prospects').first().json;
} catch(e) {
  prospectionData = { value: '?', label: 'Prospection' };
}

try {
  habitudesData = $('Process Judgment').first().json;
} catch(e) {
  habitudesData = { value: '?', label: 'Habitudes' };
}

let beeminderErrors = [];
try {
  const bpResp = $('Beeminder Prospection').first().json;
  if (bpResp.errors) beeminderErrors.push(`Prospection: ${JSON.stringify(bpResp.errors)}`);
} catch(e) { beeminderErrors.push(`Prospection: ${e.message}`); }

try {
  const bhResp = $('Beeminder Habitudes').first().json;
  if (bhResp.errors) beeminderErrors.push(`Habitudes: ${JSON.stringify(bhResp.errors)}`);
} catch(e) { beeminderErrors.push(`Habitudes: ${e.message}`); }

const ctx = $('Date Context').first().json;

const prospVal = prospectionData.value;
const prospIcon = prospVal >= 1 ? 'OK' : 'MANQUE';

const habVal = habitudesData.value;
const habIcon = habVal >= 2 ? 'OK' : (habVal > 0 ? 'PARTIEL' : 'MANQUE');

let msg = `<b>Beeminder Sync — ${ctx.today}</b>\n\n`;

msg += `<b>Prospection:</b> ${prospVal} prospect(s) [${prospIcon}]\n`;
msg += `  Objectif: 1/jour | Pledge: $5\n`;
if (prospectionData.names && prospectionData.names.length > 0) {
  msg += `  Contactes: ${prospectionData.names.join(', ')}\n`;
}

msg += `\n<b>Habitudes (Notion):</b> ${habVal}/2 [${habIcon}]\n`;
msg += `  Douche Froide: ${habitudesData.doucheFroide ? 'OK' : 'NON'}\n`;
msg += `  Journaling: ${habitudesData.journaling ? 'OK' : 'NON'}\n`;
msg += `  (Pompes envoyees separement par l app)\n`;

if (beeminderErrors.length > 0) {
  msg += `\n<b>Erreurs Beeminder:</b>\n`;
  for (const err of beeminderErrors) {
    msg += `  ${err}\n`;
  }
}

msg += `\nbeeminder.com/prinsechris`;

return [{ json: { message: msg } }];
